import json, sys
data = json.load(sys.stdin)
events = data.get('events', [])
# Find step events
steps = {}
for e in events:
    sid = e.get('step_id', '')
    status = e.get('status', e.get('type', ''))
    title = e.get('title', e.get('step_title', ''))
    if sid:
        steps[sid] = {'status': status, 'title': title or steps.get(sid, {}).get('title', '')}
for sid, info in sorted(steps.items()):
    print(f\"{sid} | {info['status']} | {info['title']}\")
